import { Button } from "@mui/material";
import Dialog from "@mui/material/Dialog";
import { MdClose } from "react-icons/md";
import Rating from "@mui/material/Rating";
import Slider from "react-slick";
import { useRef } from "react";
import "react-inner-image-zoom/lib/InnerImageZoom/styles.css";

import InnerImageZoom from "react-inner-image-zoom";

const ProducModal = (props) => {
  const zoomSliderBig = useRef();
  const zoomSlider = useRef();

  var setting2 = {
    dots: false,
    infinite: false,
    slidesToShow: 1,
    slidesToScroll: 1,
    speed: 700,
    fade: false,
    arrows: false,
  };
  return (
    <>
      <Dialog
        open={true}
        className="productModal"
        onClose={() => props.closeProductModal(false)}
      >
        <Button
          className="close"
          onClick={() => props.closeProductModal(false)}
        >
          <MdClose />
        </Button>
        <h4 className="mb-1 font-weight-bold">
          MLB - Áo thun unisex cổ tròn tay ngắn form suông hiện đại
        </h4>
        <div className="d-flex align-items-center">
          <div className="d-flex align-items-center mr-4">
            <span> Thương hiệu: </span>
            <span className="ml-2">
              <b>MLB</b>{" "}
            </span>
          </div>
          <Rating
            name="read-only"
            value={5}
            size="small"
            precision={0.5}
            readOnly
          />
        </div>
        <hr />
        <div className="row mt-2  productDetailsModal">
          <div className="col-md-5">
            <div className="productZoom">
              <Slider
                {...setting2}
                className="zomSliderBig"
                ref={zoomSliderBig}
              >
                <div className="item">
                  <InnerImageZoom
                    zoomType="hover"
                    zoomScale={1}
                    src={
                      "https://product.hstatic.net/200000642007/product/50bks_3atsl0134_1_1bb3848de8f84e66b01e56f66edd5898_51bcbdb5334245c28e49a77eaa3300b1_master.jpg"
                    }
                  />
                </div>
              </Slider>
            </div>

            <Slider></Slider>
          </div>
          <div className="col-md-5"></div>
        </div>
      </Dialog>
    </>
  );
};

export default ProducModal;
